import React, { useEffect, useState, useCallback, useRef } from "react";
import axios from "axios";
import "./App.css";

const API = "http://localhost:5000";
const DRIVE_LINK = "https://drive.google.com/file/d/1LKc-w9Ggd5I1eZ3t7Wvm9psU-4ITxHxr/view?usp=sharing";

// ─── Email template definitions ───────────────────────────────────────────────
const EMAIL_TEMPLATES = [
  {
    id: "fullstack",
    name: "Full Stack Developer",
    icon: "⚡",
    description: "Node.js · ReactJS · AWS · Modern Web",
    accent: "#2563eb",
    customNote:
      "I am excited to apply for this opportunity. My full-stack expertise in Node.js, ReactJS, and AWS Lambda makes me an ideal candidate for building scalable, production-ready applications.",
  },
  {
    id: "cti",
    name: "CTI Expert",
    icon: "📞",
    description: "Avaya · Genesys · Webex · Amazon Connect",
    accent: "#7c3aed",
    customNote:
      "With 4.7+ years specializing in CTI/telephony integrations, I have architected enterprise-grade solutions across Avaya AACC, Genesys, Webex Contact Center, and Amazon Connect — delivering real-time agent workflows, screen popups, and CRM synchronization at scale.",
  },
  {
    id: "formal",
    name: "Formal / Senior",
    icon: "🎯",
    description: "Professional tone · Enterprise-focused",
    accent: "#1d4ed8",
    customNote:
      "I am respectfully submitting my application for the above-mentioned position. I am confident that my technical background and professional experience align closely with your requirements.",
  },
  {
    id: "startup",
    name: "Startup Friendly",
    icon: "🚀",
    description: "Energetic · Fast-paced · High-growth",
    accent: "#059669",
    customNote:
      "I build fast, ship quality, and love working in environments where impact matters. My Node.js + AWS stack has powered real-time contact center solutions for enterprises — and I'm excited to bring that energy to a high-growth team.",
  },
];

// Map startup → fullstack template on backend (startup is UI-only tone variant)
const BACKEND_TEMPLATE_MAP = { fullstack: "fullstack", cti: "cti", formal: "formal", startup: "fullstack" };

function loadTemplates() {
  try { return JSON.parse(localStorage.getItem("emailTemplates") || "null") || EMAIL_TEMPLATES; } catch { return EMAIL_TEMPLATES; }
}

// ─── Email Preview Modal ──────────────────────────────────────────────────────
function EmailPreviewModal({ isOpen, onClose, html, loading }) {
  useEffect(() => {
    if (isOpen) document.body.style.overflow = "hidden";
    else document.body.style.overflow = "";
    return () => { document.body.style.overflow = ""; };
  }, [isOpen]);

  if (!isOpen) return null;
  return (
    <div className="modal-overlay" onClick={onClose} role="dialog" aria-modal="true">
      <div className="modal-box" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <div className="modal-title-row">
            <span className="modal-icon">📧</span>
            <h3 className="modal-title">Email Preview</h3>
            <span className="modal-hint">This is exactly what the recipient will see</span>
          </div>
          <button className="modal-close" onClick={onClose} aria-label="Close">✕</button>
        </div>
        <div className="modal-body">
          {loading ? (
            <div className="modal-loading"><span className="spinner spinner-dark" />Loading preview…</div>
          ) : (
            <iframe
              srcDoc={html || "<p style='padding:40px;color:#6b7280;font-family:sans-serif;'>No preview available.</p>"}
              className="email-iframe"
              title="Email Preview"
              sandbox="allow-same-origin"
            />
          )}
        </div>
      </div>
    </div>
  );
}

// ─── Template Card Grid ───────────────────────────────────────────────────────
function TemplateLibrary({ selected, onSelect, templates }) {
  return (
    <div className="template-grid">
      {templates.map((t) => (
        <button
          key={t.id}
          type="button"
          className={`template-card ${selected === t.id ? "template-card-active" : ""}`}
          style={selected === t.id ? { "--card-accent": t.accent, borderColor: t.accent } : {}}
          onClick={() => onSelect(t)}
        >
          <span className="tcard-icon">{t.icon}</span>
          <span className="tcard-name">{t.name}</span>
          <span className="tcard-desc">{t.description}</span>
        </button>
      ))}
    </div>
  );
}

// ─── Dark Mode Toggle ─────────────────────────────────────────────────────────
function DarkModeToggle({ dark, onToggle }) {
  return (
    <button className={`dark-toggle ${dark ? "dark-toggle-on" : ""}`} onClick={onToggle} title="Toggle dark mode" aria-label="Toggle dark mode">
      <span className="toggle-track">
        <span className="toggle-thumb">{dark ? "🌙" : "☀️"}</span>
      </span>
    </button>
  );
}

// ─── Search Bar ───────────────────────────────────────────────────────────────
function SearchBar({ value, onChange }) {
  return (
    <div className="search-bar-wrap">
      <span className="search-icon">🔍</span>
      <input
        className="search-input"
        type="text"
        placeholder="Search applied jobs by company, role, or email…"
        value={value}
        onChange={(e) => onChange(e.target.value)}
      />
      {value && (
        <button className="search-clear" onClick={() => onChange("")} aria-label="Clear search">✕</button>
      )}
    </div>
  );
}

// ─── Sent Applications Log ────────────────────────────────────────────────────
function SentLog({ log, trackingRecords, searchQuery }) {
  const filtered = searchQuery
    ? log.filter(
        (e) =>
          e.company?.toLowerCase().includes(searchQuery.toLowerCase()) ||
          e.role?.toLowerCase().includes(searchQuery.toLowerCase()) ||
          e.email?.toLowerCase().includes(searchQuery.toLowerCase())
      )
    : log;

  if (!log.length) return null;

  return (
    <div className="sent-log">
      <div className="log-header-row">
        <h3 className="log-title">📋 Applied Jobs Log</h3>
        <span className="log-count">{filtered.length} / {log.length}</span>
      </div>
      {filtered.length === 0 ? (
        <p className="no-results">No results for "{searchQuery}"</p>
      ) : (
        <div className="log-list">
          {filtered.map((entry, i) => {
            const tracking = trackingRecords.find((r) => r.hrEmail === entry.email && r.company === entry.company);
            return (
              <div key={i} className="log-item">
                <div className="log-main">
                  <span className="log-company">{entry.company}</span>
                  {entry.role && <span className="log-role">{entry.role}</span>}
                  <span className={`log-badge log-badge-${entry.type}`}>
                    {entry.type === "application" ? "Applied" : "Follow-up"}
                  </span>
                  {tracking?.opened && (
                    <span className="log-badge log-badge-opened" title={`Opened at ${new Date(tracking.openedAt).toLocaleString()}`}>
                      👁 Opened
                    </span>
                  )}
                </div>
                <div className="log-meta">
                  <span>{entry.email}</span>
                  <span>{entry.time}</span>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ─── Application Form ─────────────────────────────────────────────────────────
function ApplicationForm({ onSent, templates, onPreviewRequest }) {
  const [form, setForm] = useState({
    hrEmail: "", hrName: "", company: "", role: "", customNote: "",
  });
  const [templateId, setTemplateId] = useState("fullstack");
  const [mode, setMode] = useState("now");
  const [scheduledTime, setScheduledTime] = useState("");
  const [readReceipt, setReadReceipt] = useState(false);
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState(null);

  const handle = (e) => {
    setForm((p) => ({ ...p, [e.target.name]: e.target.value }));
    if (status) setStatus(null);
  };

  const selectTemplate = (t) => {
    setTemplateId(t.id);
    setForm((p) => ({ ...p, customNote: t.customNote }));
  };

  const submit = async (e) => {
    e.preventDefault();
    if (!form.hrEmail || !form.company) return;
    setLoading(true);
    setStatus(null);
    try {
      if (mode === "schedule") {
        if (!scheduledTime) throw new Error("Please choose a date and time for scheduling.");
        const res = await axios.post(`${API}/api/schedule-email`, {
          ...form,
          templateType: BACKEND_TEMPLATE_MAP[templateId] || "fullstack",
          readReceipt,
          scheduledTime,
        });
        setStatus({ type: "success", text: res.data.message });
      } else {
        const res = await axios.post(`${API}/api/send-application`, {
          ...form,
          templateType: BACKEND_TEMPLATE_MAP[templateId] || "fullstack",
          readReceipt,
        });
        setStatus({ type: "success", text: res.data.message });
        onSent({
          type: "application",
          company: form.company,
          role: form.role,
          email: form.hrEmail,
          time: new Date().toLocaleString(),
          messageId: res.data.messageId,
          subject: form.role
            ? `Application for ${form.role} Position — Anav Bansal`
            : "Job Application — Anav Bansal",
          hrName: form.hrName,
          hrEmail: form.hrEmail,
        });
      }
      setForm({ hrEmail: "", hrName: "", company: "", role: "", customNote: "" });
      setScheduledTime("");
    } catch (err) {
      setStatus({ type: "error", text: err.response?.data?.message || "Failed. Check backend." });
    } finally {
      setLoading(false);
    }
  };

  const valid = form.hrEmail && form.company;
  const activeTemplate = EMAIL_TEMPLATES.find((t) => t.id === templateId);

  return (
    <form className="mailer-form" onSubmit={submit} noValidate>
      {/* Template Library */}
      <div className="form-group">
        <label className="form-label">Email Template</label>
        <TemplateLibrary selected={templateId} onSelect={selectTemplate} templates={templates} />
      </div>

      {/* Delivery Mode */}
      <div className="form-group">
        <label className="form-label">Delivery Mode</label>
        <div className="chip-row">
          <button type="button" className={`chip ${mode === "now" ? "chip-active" : ""}`} onClick={() => setMode("now")}>
            ⚡ Send Now
          </button>
          <button type="button" className={`chip ${mode === "schedule" ? "chip-active" : ""}`} onClick={() => setMode("schedule")}>
            🗓 Schedule
          </button>
        </div>
      </div>

      {mode === "schedule" && (
        <div className="form-group">
          <label className="form-label" htmlFor="scheduledTime">
            <span className="lbadge">Required</span> Date &amp; Time
          </label>
          <input
            id="scheduledTime"
            type="datetime-local"
            min={new Date(Date.now() + 60000).toISOString().slice(0, 16)}
            value={scheduledTime}
            onChange={(e) => setScheduledTime(e.target.value)}
            className="form-input"
          />
        </div>
      )}

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="hrEmail">
            <span className="lbadge">Required</span> HR / Recruiter Email
          </label>
          <input id="hrEmail" name="hrEmail" type="email" value={form.hrEmail} onChange={handle}
            placeholder="recruiter@company.com" className="form-input" required disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="hrName">
            <span className="lbadge lbadge-opt">Optional</span> HR Name
          </label>
          <input id="hrName" name="hrName" type="text" value={form.hrName} onChange={handle}
            placeholder="e.g. Priya Sharma" className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="company">
            <span className="lbadge">Required</span> Company Name
          </label>
          <input id="company" name="company" type="text" value={form.company} onChange={handle}
            placeholder="e.g. Google, Infosys" className="form-input" required disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="role">
            <span className="lbadge lbadge-opt">Optional</span> Role / Position
          </label>
          <input id="role" name="role" type="text" value={form.role} onChange={handle}
            placeholder="e.g. Senior Full Stack Developer" className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-group">
        <label className="form-label" htmlFor="customNote">
          <span className="lbadge lbadge-opt">Optional</span> Custom Note
          <span className="label-hint">Inserted in the email body · auto-filled from template</span>
        </label>
        <textarea id="customNote" name="customNote" value={form.customNote} onChange={handle}
          placeholder="Add a personalised line…" className="form-textarea" rows={3} disabled={loading} />
      </div>

      {/* Read receipt toggle */}
      <div className="form-group">
        <label className="toggle-label">
          <span className="toggle-switch-wrap">
            <input type="checkbox" checked={readReceipt} onChange={(e) => setReadReceipt(e.target.checked)} className="toggle-checkbox" />
            <span className="toggle-switch" />
          </span>
          <span className="toggle-text">Request Read Receipt</span>
          <span className="label-hint">Asks recipient's email client to notify on open</span>
        </label>
      </div>

      {/* Inline preview card */}
      <div className="preview-card">
        <div className="preview-card-header">
          <p className="preview-title">📧 Email Preview</p>
          <button
            type="button"
            className="btn-preview"
            onClick={() => onPreviewRequest({ ...form, templateType: BACKEND_TEMPLATE_MAP[templateId] || "fullstack" })}
          >
            View Full Email ↗
          </button>
        </div>
        <p className="preview-subject">
          <strong>Subject:</strong>{" "}
          {form.role ? `Application for ${form.role} Position — Anav Bansal` : "Job Application — Anav Bansal (Senior Full Stack Developer)"}
        </p>
        <p className="preview-line"><strong>To:</strong> {form.hrEmail || "—"}{form.hrName && ` (${form.hrName})`}</p>
        <p className="preview-line">
          <strong>Template:</strong>{" "}
          <span style={{ color: activeTemplate?.accent }}>{activeTemplate?.icon} {activeTemplate?.name}</span>
        </p>
        <p className="preview-line">
          <strong>Attachment:</strong> Anav_Bansal_Resume.pdf &nbsp;
          <a href={DRIVE_LINK} target="_blank" rel="noreferrer" className="drive-link">+ Drive Link ↗</a>
        </p>
      </div>

      {status && (
        <div className={`alert alert-${status.type}`} role="alert">
          <span className="alert-icon">{status.type === "success" ? "✓" : "✕"}</span>
          <span>{status.text}</span>
        </div>
      )}

      <div className="form-footer">
        <button type="submit" className={`btn-primary ${loading ? "loading" : ""}`} disabled={loading || !valid}>
          {loading ? <><span className="spinner" /> Sending…</> : <><span className="btn-arrow">↑</span> {mode === "schedule" ? "Schedule Email" : "Send Application"}</>}
        </button>
        <button type="button" className="btn-ghost" disabled={loading}
          onClick={() => { setForm({ hrEmail: "", hrName: "", company: "", role: "", customNote: "" }); setStatus(null); }}>
          Clear
        </button>
      </div>
    </form>
  );
}

// ─── Follow-up Form ───────────────────────────────────────────────────────────
function FollowUpForm({ sentLog, onSent }) {
  const [selectedIdx, setSelectedIdx] = useState("");
  const [form, setForm] = useState({
    hrEmail: "", hrName: "", company: "", role: "",
    originalDate: "", customNote: "", originalMessageId: "", originalSubject: "",
  });
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState(null);

  const handle = (e) => {
    setForm((p) => ({ ...p, [e.target.name]: e.target.value }));
    if (status) setStatus(null);
  };

  const selectApplication = (idx) => {
    setSelectedIdx(idx);
    if (idx === "") return;
    const entry = sentLog[parseInt(idx)];
    setForm({
      hrEmail: entry.hrEmail || "",
      hrName: entry.hrName || "",
      company: entry.company || "",
      role: entry.role || "",
      originalDate: entry.time || "",
      customNote: "",
      originalMessageId: entry.messageId || "",
      originalSubject: entry.subject || "",
    });
    if (status) setStatus(null);
  };

  const submit = async (e) => {
    e.preventDefault();
    if (!form.hrEmail || !form.company) return;
    setLoading(true);
    setStatus(null);
    try {
      const res = await axios.post(`${API}/api/send-followup`, form);
      setStatus({ type: "success", text: res.data.message });
      onSent({
        type: "followup",
        company: form.company,
        role: form.role,
        email: form.hrEmail,
        time: new Date().toLocaleString(),
        messageId: res.data.messageId,
        subject: form.originalSubject,
        hrName: form.hrName,
        hrEmail: form.hrEmail,
      });
      setForm({ hrEmail: "", hrName: "", company: "", role: "", originalDate: "", customNote: "", originalMessageId: "", originalSubject: "" });
      setSelectedIdx("");
    } catch (err) {
      setStatus({ type: "error", text: err.response?.data?.message || "Failed to send." });
    } finally {
      setLoading(false);
    }
  };

  const valid = form.hrEmail && form.company;
  const appliedEntries = sentLog.filter((e) => e.type === "application");

  return (
    <form className="mailer-form" onSubmit={submit} noValidate>
      {appliedEntries.length > 0 && (
        <div className="form-group">
          <label className="form-label" htmlFor="selectApp">
            <span className="lbadge lbadge-green">Quick Fill</span> Select from sent applications
          </label>
          <select id="selectApp" className="form-input form-select" value={selectedIdx}
            onChange={(e) => selectApplication(e.target.value)} disabled={loading}>
            <option value="">— Choose a previous application —</option>
            {sentLog.map((e, i) =>
              e.type === "application" ? (
                <option key={i} value={i}>{e.company}{e.role ? ` · ${e.role}` : ""} ({e.email}) — {e.time}</option>
              ) : null
            )}
          </select>
        </div>
      )}

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="fu-hrEmail"><span className="lbadge">Required</span> HR Email</label>
          <input id="fu-hrEmail" name="hrEmail" type="email" value={form.hrEmail} onChange={handle}
            placeholder="recruiter@company.com" className="form-input" required disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="fu-hrName"><span className="lbadge lbadge-opt">Optional</span> HR Name</label>
          <input id="fu-hrName" name="hrName" type="text" value={form.hrName} onChange={handle}
            placeholder="e.g. Priya Sharma" className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="fu-company"><span className="lbadge">Required</span> Company</label>
          <input id="fu-company" name="company" type="text" value={form.company} onChange={handle}
            placeholder="Company Name" className="form-input" required disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="fu-role"><span className="lbadge lbadge-opt">Optional</span> Role</label>
          <input id="fu-role" name="role" type="text" value={form.role} onChange={handle}
            placeholder="e.g. Senior Full Stack Developer" className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-row">
        <div className="form-group">
          <label className="form-label" htmlFor="fu-date"><span className="lbadge lbadge-opt">Optional</span> Original Application Date</label>
          <input id="fu-date" name="originalDate" type="text" value={form.originalDate} onChange={handle}
            placeholder="e.g. 25 May 2026" className="form-input" disabled={loading} />
        </div>
        <div className="form-group">
          <label className="form-label" htmlFor="fu-msgid">
            <span className="lbadge lbadge-opt">Optional</span> Original Message ID
            <span className="label-hint">Auto-filled via Quick Fill</span>
          </label>
          <input id="fu-msgid" name="originalMessageId" type="text" value={form.originalMessageId} onChange={handle}
            placeholder="<msgid@gmail.com>" className="form-input" disabled={loading} />
        </div>
      </div>

      <div className="form-group">
        <label className="form-label" htmlFor="fu-note"><span className="lbadge lbadge-opt">Optional</span> Custom Note</label>
        <textarea id="fu-note" name="customNote" value={form.customNote} onChange={handle}
          placeholder="e.g. I wanted to reiterate my enthusiasm…" className="form-textarea" rows={3} disabled={loading} />
      </div>

      {form.originalMessageId && (
        <div className="thread-notice">
          <span className="thread-icon">🧵</span>
          <span>This follow-up will be sent <strong>in the same email thread</strong> as the original application.</span>
        </div>
      )}

      {status && (
        <div className={`alert alert-${status.type}`} role="alert">
          <span className="alert-icon">{status.type === "success" ? "✓" : "✕"}</span>
          <span>{status.text}</span>
        </div>
      )}

      <div className="form-footer">
        <button type="submit" className={`btn-followup ${loading ? "loading" : ""}`} disabled={loading || !valid}>
          {loading ? <><span className="spinner" /> Sending…</> : <><span className="btn-arrow">↑</span> Send Follow-up</>}
        </button>
        <button type="button" className="btn-ghost" disabled={loading}
          onClick={() => { setForm({ hrEmail: "", hrName: "", company: "", role: "", originalDate: "", customNote: "", originalMessageId: "", originalSubject: "" }); setSelectedIdx(""); setStatus(null); }}>
          Clear
        </button>
      </div>
    </form>
  );
}

