function BulkSendPanel() {
  const [text, setText] = useState("");
  const [templateId, setTemplateId] = useState("fullstack");
  const [result, setResult] = useState(null);
  const [running, setRunning] = useState(false);

  const preview = text.split("\n").filter(Boolean).map((line) => {
    const [hrEmail = "", hrName = "", company = "", role = ""] = line.split(",");
    return { hrEmail: hrEmail.trim(), hrName: hrName.trim(), company: company.trim(), role: role.trim() };
  });

  const sendBulk = async () => {
    setRunning(true); setResult(null);
    try {
      const res = await axios.post(`${API}/api/bulk-send`, {
        emailList: preview,
        templateType: BACKEND_TEMPLATE_MAP[templateId] || "fullstack",
      });
      setResult(res.data);
    } catch (e) {
      setResult({ success: false, message: e.response?.data?.message || e.message });
    } finally {
      setRunning(false);
    }
  };

  return (
    <div className="mailer-form">
      <div className="form-group">
        <label className="form-label">Template</label>
        <div className="chip-row">
          {EMAIL_TEMPLATES.map((t) => (
            <button key={t.id} type="button" className={`chip ${templateId === t.id ? "chip-active" : ""}`} onClick={() => setTemplateId(t.id)}>
              {t.icon} {t.name}
            </button>
          ))}
        </div>
      </div>
      <div className="form-group">
        <label className="form-label">Bulk Email List</label>
        <textarea className="form-textarea" rows={8} value={text} onChange={(e) => setText(e.target.value)}
          placeholder={"hr@google.com, Priya Sharma, Google, Senior Developer\nrecruiter@startup.com, , Startup XYZ, Node.js Engineer"} />
      </div>
      {preview.length > 0 && (
        <div className="preview-card">
          <p className="preview-title">Preview ({preview.length} recipients)</p>
          {preview.slice(0, 5).map((item, idx) => (
            <p key={idx} className="preview-line">{idx + 1}. {item.hrEmail || "—"} · {item.company || "—"} · {item.role || "—"}</p>
          ))}
          {preview.length > 5 && <p className="preview-line">…and {preview.length - 5} more</p>}
        </div>
      )}
      <div className="form-footer">
        <button type="button" className="btn-primary" disabled={running || preview.length === 0} onClick={sendBulk}>
          {running ? <><span className="spinner" /> Sending…</> : `📦 Send to ${preview.length} Recipients`}
        </button>
      </div>
      {result && (
        <div className={`alert ${result.success ? "alert-success" : "alert-error"}`}>
          <span className="alert-icon">{result.success ? "✓" : "✕"}</span>
          <span>{result.success ? `Sent ${result.sent}/${result.total} emails successfully.` : result.message}</span>
        </div>
      )}
    </div>
  );
}

