// ─── Inbox Panel ──────────────────────────────────────────────────────────────
function InboxPanel({ sentLog, trackingRecords }) {
  const [messages, setMessages] = useState([]);
  const [showAllInbox, setShowAllInbox] = useState(false);
  const [inboxSearch, setInboxSearch] = useState("");
  const [loading, setLoading] = useState(false);

  const connect = () => { window.location.href = `${API}/api/gmail/auth`; };

  const fetchInbox = useCallback(async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/api/gmail/inbox`);
      if (res.data.success) setMessages(res.data.messages || []);
    } catch {}
    finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchInbox(); }, [fetchInbox]);

  const appliedEmails = new Set([
    ...sentLog.map((e) => e.email),
    ...trackingRecords.map((r) => r.hrEmail),
  ]);

  const filtered = messages.filter((m) => {
    const emailMatch = showAllInbox || (() => {
      const fromEmail = (m.from.match(/<(.+?)>/) || m.from.match(/\S+@\S+/) || [])[1] || m.from;
      return appliedEmails.has(fromEmail);
    })();
    const searchMatch = !inboxSearch ||
      m.subject?.toLowerCase().includes(inboxSearch.toLowerCase()) ||
      m.from?.toLowerCase().includes(inboxSearch.toLowerCase());
    return emailMatch && searchMatch;
  });

  return (
    <div className="mailer-form">
      <div className="inbox-toolbar">
        <button type="button" className="btn-primary btn-sm" onClick={connect}>Connect Gmail</button>
        <button type="button" className="btn-ghost btn-sm" onClick={fetchInbox} disabled={loading}>
          {loading ? "Refreshing…" : "↻ Refresh"}
        </button>
        <label className="toggle-label toggle-label-inline">
          <span className="toggle-switch-wrap">
            <input type="checkbox" checked={showAllInbox} onChange={(e) => setShowAllInbox(e.target.checked)} className="toggle-checkbox" />
            <span className="toggle-switch" />
          </span>
          <span className="toggle-text">Show all inbox</span>
        </label>
      </div>

      <div className="form-group">
        <div className="search-bar-wrap">
          <span className="search-icon">🔍</span>
          <input className="search-input" type="text" placeholder="Search inbox…"
            value={inboxSearch} onChange={(e) => setInboxSearch(e.target.value)} />
        </div>
      </div>

      {!showAllInbox && appliedEmails.size === 0 && (
        <div className="inbox-hint">
          No applied jobs in your session log yet. Send an application first, or toggle "Show all inbox".
        </div>
      )}

      {messages.length > 0 ? (
        <div className="preview-card">
          <div className="inbox-filter-row">
            <p className="preview-title">
              {showAllInbox ? `All Inbox (${filtered.length})` : `Applied Jobs Inbox (${filtered.length})`}
            </p>
          </div>
          {filtered.length === 0 ? (
            <p className="preview-line">No matching messages.</p>
          ) : (
            filtered.map((m) => (
              <div key={m.id} className={`log-item inbox-item ${!m.isRead ? "inbox-unread" : ""}`}>
                <div className="log-main">
                  <strong className="inbox-subject">{m.subject}</strong>
                  <span className={`log-badge ${m.isRead ? "log-badge-muted" : "log-badge-application"}`}>
                    {m.isRead ? "Read" : "Unread"}
                  </span>
                  {m.isReply && <span className="log-badge log-badge-followup">Reply</span>}
                </div>
                <div className="log-meta">
                  <span>{m.from}</span>
                  <span>{m.date}</span>
                </div>
                <p className="preview-line inbox-snippet">{m.snippet}</p>
              </div>
            ))
          )}
        </div>
      ) : (
        <p className="preview-line">Connect Gmail to load inbox.</p>
      )}
    </div>
  );
}

// ─── Scheduled Panel ──────────────────────────────────────────────────────────
function ScheduledPanel() {
  const [jobs, setJobs] = useState([]);
  useEffect(() => {
    axios.get(`${API}/api/scheduled-emails`).then((res) => setJobs(res.data.jobs || [])).catch(() => setJobs([]));
  }, []);
  const remove = async (jobId) => {
    await axios.delete(`${API}/api/scheduled-emails/${jobId}`);
    setJobs((p) => p.filter((j) => j.jobId !== jobId));
  };
  const pending = jobs.filter((j) => j.status === "pending");
  if (!pending.length) return null;
  return (
    <div className="sent-log">
      <h3 className="log-title">🗓 Scheduled Emails ({pending.length})</h3>
      <div className="log-list">
        {pending.map((job) => (
          <div key={job.jobId} className="log-item">
            <div className="log-main">
              <span className="log-company">{job.emailData.company}</span>
              {job.emailData.role && <span className="log-role">{job.emailData.role}</span>}
              <span className="log-badge log-badge-scheduled">Scheduled</span>
            </div>
            <div className="log-meta">
              <span>{job.emailData.hrEmail}</span>
              <span>📅 {new Date(job.scheduledTime).toLocaleString("en-IN")}</span>
            </div>
            <button type="button" className="btn-ghost btn-sm cancel-btn" onClick={() => remove(job.jobId)}>Cancel</button>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── Reminders Panel ──────────────────────────────────────────────────────────
function RemindersPanel() {
  const [reminders, setReminders] = useState([]);
  useEffect(() => { setReminders(JSON.parse(localStorage.getItem("jobMailerReminders") || "[]")); }, []);
  const remove = (id) => {
    const updated = reminders.filter((x) => x.id !== id);
    localStorage.setItem("jobMailerReminders", JSON.stringify(updated));
    setReminders(updated);
  };
  const snooze = (id) => {
    const updated = reminders.map((x) =>
      x.id === id ? { ...x, reminderDate: new Date(new Date(x.reminderDate).getTime() + 2 * 86400000).toISOString().slice(0, 10), notified: false } : x
    );
    localStorage.setItem("jobMailerReminders", JSON.stringify(updated));
    setReminders(updated);
  };
  if (!reminders.length) return null;
  return (
    <div className="sent-log">
      <h3 className="log-title">🔔 Reminders ({reminders.length})</h3>
      <div className="log-list">
        {reminders.map((item) => (
          <div key={item.id} className="log-item">
            <div className="log-main">
              <strong>{item.company}</strong>
              <span className="log-badge log-badge-scheduled">{item.reminderDate}</span>
            </div>
            <p className="preview-line">{item.note || "No note"}</p>
            <div className="form-footer" style={{ paddingTop: 0 }}>
              <button type="button" className="btn-ghost btn-sm" onClick={() => snooze(item.id)}>Snooze +2d</button>
              <button type="button" className="btn-ghost btn-sm" onClick={() => remove(item.id)}>Delete</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

