          <div className="profile-right">
            <div className="profile-exp">
              <span className="exp-num">4.7+</span>
              <span className="exp-label">Years Exp.</span>
            </div>
            <DarkModeToggle dark={darkMode} onToggle={() => setDarkMode((d) => !d)} />
          </div>
        </header>

        {/* Global Search Bar */}
        <SearchBar value={searchQuery} onChange={setSearchQuery} />

        {/* Tabs */}
        <div className="tabs">
          {TABS.map((t) => (
            <button
              key={t.id}
              className={`tab ${tab === t.id ? "tab-active" : ""} ${tab === t.id && t.id === "followup" ? "tab-followup" : ""} ${tab === t.id && t.id === "jobs" ? "tab-jobs" : ""}`}
              onClick={() => setTab(t.id)}
            >
              <span className="tab-icon">{t.icon}</span>
              {t.label}
            </button>
          ))}
        </div>

        {/* Main Card */}
        <div className="card">
          {tab === "apply" && (
            <>
              <div className="card-header">
                <div>
                  <h2 className="card-title">Job Application Email</h2>
                  <p className="card-subtitle">Choose a template, fill in details, and send with resume attached</p>
                </div>
                <div className="attachment-badge"><span>📎</span> Resume Auto-Attached</div>
              </div>
              <ApplicationForm onSent={addToLog} templates={templates} onPreviewRequest={handlePreviewRequest} />
            </>
          )}

          {tab === "followup" && (
            <>
              <div className="card-header">
                <div>
                  <h2 className="card-title">Follow-up Email</h2>
                  <p className="card-subtitle">Send a follow-up in the same thread as your original application</p>
                </div>
                <div className="attachment-badge attachment-badge-green"><span>🧵</span> Thread Reply</div>
              </div>
              <FollowUpForm sentLog={sentLog} onSent={addToLog} />
            </>
          )}

          {tab === "jobs" && (
            <>
              <div className="card-header">
                <div>
                  <h2 className="card-title">Find Jobs</h2>
                  <p className="card-subtitle">Search Naukri, Indeed, LinkedIn and more · Apply directly via Job Mailer</p>
                </div>
                <div className="attachment-badge attachment-badge-purple"><span>🔍</span> Job Search</div>
              </div>
              <JobSearchPanel onFillApply={handleFillApply} />
            </>
          )}

          {tab === "bulk" && (
            <>
              <div className="card-header">
                <div>
                  <h2 className="card-title">Bulk Send</h2>
                  <p className="card-subtitle">Paste a CSV list of recipients and send sequentially</p>
                </div>
                <div className="attachment-badge"><span>📦</span> Bulk Mailer</div>
              </div>
              <BulkSendPanel />
            </>
          )}

          {tab === "inbox" && (
            <>
              <div className="card-header">
                <div>
                  <h2 className="card-title">Inbox</h2>
                  <p className="card-subtitle">Shows replies from companies you've applied to · Toggle for full inbox</p>
                </div>
                <div className="attachment-badge"><span>📥</span> Gmail API</div>
              </div>
              <InboxPanel sentLog={sentLog} trackingRecords={trackingRecords} />
            </>
          )}
        </div>

        <ScheduledPanel />
        <RemindersPanel />
        <SentLog log={sentLog} trackingRecords={trackingRecords} searchQuery={searchQuery} />
      </div>
    </div>
  );
}
